class Solution {
public:
    int equalPairs(vector<vector<int>>& grid) {
        int size = grid.size();
        std::map<std::vector<int>, int> pair;
        int count = 0;

        for (auto row : grid) {
            pair[row]++;
        }

        std::vector<int> myvector(size); 
        for (int x = 0; x < size; x++) {
            for (int y = 0; y < size; y++) {
                myvector[y] = grid[y][x];
            }
            if (pair.find(myvector) != pair.end()) {
                count += pair[myvector];
            }
        }

        return count;
    }
};
